theory OnOffCluster_Matter
begin

// Cluster: On/Off
// Cluster ID: 0x0006
// Generated from Matter On/Off cluster specification (Lighting, DeadFront, OffOnly features)

/* ------------------------------------------------------------------------- */
/* Builtins                                                                  */
/* ------------------------------------------------------------------------- */

builtins: hashing

/* ------------------------------------------------------------------------- */
/* Functions and symbolic domains                                            */
/* ------------------------------------------------------------------------- */

// Booleans
functions: b_true/0, b_false/0

// Timer abstraction categories for uint16 OnTime and OffWaitTime
// 't_zero'   : concrete 0
// 't_pos'    : concrete 1..0xFFFE
// 't_ffff'   : concrete 0xFFFF (disabled auto-decrement)
functions: t_zero/0, t_pos/0, t_ffff/0

// Timer process state for OnWithTimedOff state machine
// 'ts_idle'        : no active OnWithTimedOff-related updates
// 'ts_timed_on'    : Timed On phase (OnOff = TRUE, OnTime > 0)
// 'ts_delayed_off' : Delayed Off phase (OnOff = FALSE, OffWaitTime > 0)
functions: ts_idle/0, ts_timed_on/0, ts_delayed_off/0

// Features of the OnOff cluster
functions:
  f_base/0,        // no special features
  f_lt/0,          // Lighting only (LT)
  f_df/0,          // Dead Front only (DF)
  f_offonly/0,     // OffOnly only
  f_lt_df/0        // LT + DF

// StartUpOnOffEnum abstraction (values from spec)
functions:
  suo_off/0,       // StartUpOnOffEnum.Off (0x00)
  suo_on/0,        // StartUpOnOffEnum.On (0x01)
  suo_toggle/0,    // StartUpOnOffEnum.Toggle (0x02)
  suo_null/0       // "null" → restore previous OnOff at power-up

// OnWithTimedOff OnOffControlBitmap abstraction
// We only care about AcceptOnlyWhenOn bit
functions:
  ctl_none/0,              // AcceptOnlyWhenOn == 0
  ctl_accept_only_when_on/0 // AcceptOnlyWhenOn == 1

// Abstract command parameters for OnWithTimedOff fields
// We only symbolically distinguish the effect on timers (zero vs positive vs disabled)
functions:
  field_zero/0,   // 0
  field_pos/0,    // 1..0xFFFE
  field_ffff/0    // 0xFFFF

// Scenes / external interactions (symbolic)
functions:
  op_invoke/0

/* ------------------------------------------------------------------------- */
/* State Fact                                                                */
/* ------------------------------------------------------------------------- */

// Unified cluster state fact. The arity is fixed across all rules:
//
// St_Cluster(tid,
//            OnOff,              // b_true / b_false
//            GlobalSceneControl, // b_true / b_false (meaningful only if LT feature present)
//            OnTime,             // t_zero / t_pos / t_ffff
//            OffWaitTime,        // t_zero / t_pos / t_ffff
//            TimerState,         // ts_idle / ts_timed_on / ts_delayed_off
//            FeatureConf,        // f_base / f_lt / f_df / f_offonly / f_lt_df
//            StartUpOnOff)       // suo_off / suo_on / suo_toggle / suo_null
//
// NOTE: Only Lighting-capable feature configurations (f_lt, f_lt_df) actually
// use GlobalSceneControl, OnTime, OffWaitTime, TimerState in accordance with
// the spec. For non-LT configs, these are ignored but kept for arity-uniformity.

/* ------------------------------------------------------------------------- */
/* Initialisation                                                            */
/* ------------------------------------------------------------------------- */

rule Init_Cluster_Base:
  // Base feature set, no LT/DF/OFFONLY
  [ Fr(~tid) ]
--[ ClusterInit(~tid) ]->
  [ St_Cluster(~tid,
               b_false,     // OnOff default FALSE
               b_false,     // GlobalSceneControl unused in Base; keep FALSE
               t_zero,      // OnTime default 0 (unused)
               t_zero,      // OffWaitTime default 0 (unused)
               ts_idle,     // no active timers
               f_base,
               suo_null) ]  // default StartUpOnOff := null (restore previous)

rule Init_Cluster_LT:
  // Lighting feature enabled (no DF, no OFFONLY)
  [ Fr(~tid) ]
--[ ClusterInit(~tid) ]->
  [ St_Cluster(~tid,
               b_false,     // OnOff default FALSE
               b_true,      // GlobalSceneControl default TRUE (spec)
               t_zero,      // OnTime default 0
               t_zero,      // OffWaitTime default 0
               ts_idle,
               f_lt,
               suo_null) ]

rule Init_Cluster_DF:
  // DeadFront only
  [ Fr(~tid) ]
--[ ClusterInit(~tid) ]->
  [ St_Cluster(~tid,
               b_false,
               b_false,
               t_zero,
               t_zero,
               ts_idle,
               f_df,
               suo_null) ]

rule Init_Cluster_OffOnly:
  // OffOnly feature (no LT/DF)
  [ Fr(~tid) ]
--[ ClusterInit(~tid) ]->
  [ St_Cluster(~tid,
               b_false,
               b_false,
               t_zero,
               t_zero,
               ts_idle,
               f_offonly,
               suo_null) ]

rule Init_Cluster_LT_DF:
  // Lighting + DeadFront
  [ Fr(~tid) ]
--[ ClusterInit(~tid) ]->
  [ St_Cluster(~tid,
               b_false,
               b_true,
               t_zero,
               t_zero,
               ts_idle,
               f_lt_df,
               suo_null) ]

/* ------------------------------------------------------------------------- */
/* Power-up behavior controlled by StartUpOnOffEnum                         */
/* ------------------------------------------------------------------------- */

// PowerUp: StartUpOnOff = suo_off → OnOff := FALSE
rule PowerUp_Off:
  [ St_Cluster(~tid, OnOff, GSC, OT, OW, TS, F, suo_off) ]
--[ PowerUp(~tid, 'StartUpOff') ]->
  [ St_Cluster(~tid, b_false, GSC, OT, OW, ts_idle, F, suo_off) ]

// PowerUp: StartUpOnOff = suo_on → OnOff := TRUE
rule PowerUp_On:
  [ St_Cluster(~tid, OnOff, GSC, OT, OW, TS, F, suo_on) ]
--[ PowerUp(~tid, 'StartUpOn') ]->
  [ St_Cluster(~tid, b_true, GSC, OT, OW, ts_idle, F, suo_on) ]

// PowerUp: StartUpOnOff = suo_toggle → OnOff := NOT previous OnOff
rule PowerUp_Toggle_From_Off:
  [ St_Cluster(~tid, b_false, GSC, OT, OW, TS, F, suo_toggle) ]
--[ PowerUp(~tid, 'StartUpToggle') ]->
  [ St_Cluster(~tid, b_true, GSC, OT, OW, ts_idle, F, suo_toggle) ]

rule PowerUp_Toggle_From_On:
  [ St_Cluster(~tid, b_true, GSC, OT, OW, TS, F, suo_toggle) ]
--[ PowerUp(~tid, 'StartUpToggle') ]->
  [ St_Cluster(~tid, b_false, GSC, OT, OW, ts_idle, F, suo_toggle) ]

// PowerUp: StartUpOnOff = suo_null → restore previous OnOff (no change)
rule PowerUp_Null:
  [ St_Cluster(~tid, OnOff, GSC, OT, OW, TS, F, suo_null) ]
--[ PowerUp(~tid, 'StartUpNull') ]->
  [ St_Cluster(~tid, OnOff, GSC, OT, OW, ts_idle, F, suo_null) ]

/* ------------------------------------------------------------------------- */
/* Off command                                                               */
/* ------------------------------------------------------------------------- */

// Spec (all features): OnOff := FALSE
// If LT is present: OnTime := 0; OffWaitTime unaffected; TimerState := ts_idle
// OffOnly allows Off

// Base: OFF, no timers
rule Cmd_Off_Base:
  [ St_Cluster(~tid, _, GSC, OT, OW, TS, f_base, SUO) ]
--[ Command(~tid, 'Off'), CmdSucceeded(~tid, 'Off') ]->
  [ St_Cluster(~tid, b_false, GSC, OT, OW, ts_idle, f_base, SUO) ]

// DF only: same as base
rule Cmd_Off_DF:
  [ St_Cluster(~tid, _, GSC, OT, OW, TS, f_df, SUO) ]
--[ Command(~tid, 'Off'), CmdSucceeded(~tid, 'Off') ]->
  [ St_Cluster(~tid, b_false, GSC, OT, OW, ts_idle, f_df, SUO) ]

// OffOnly: Off permitted
rule Cmd_Off_OffOnly:
  [ St_Cluster(~tid, _, GSC, OT, OW, TS, f_offonly, SUO) ]
--[ Command(~tid, 'Off'), CmdSucceeded(~tid, 'Off') ]->
  [ St_Cluster(~tid, b_false, GSC, OT, OW, ts_idle, f_offonly, SUO) ]

// LT: OnOff := FALSE, OnTime := 0, Timer idle
rule Cmd_Off_LT:
  [ St_Cluster(~tid, _, GSC, OT, OW, TS, f_lt, SUO) ]
--[ Command(~tid, 'Off'), CmdSucceeded(~tid, 'Off') ]->
  [ St_Cluster(~tid, b_false, GSC, t_zero, OW, ts_idle, f_lt, SUO) ]

// LT+DF: same as LT
rule Cmd_Off_LT_DF:
  [ St_Cluster(~tid, _, GSC, OT, OW, TS, f_lt_df, SUO) ]
--[ Command(~tid, 'Off'), CmdSucceeded(~tid, 'Off') ]->
  [ St_Cluster(~tid, b_false, GSC, t_zero, OW, ts_idle, f_lt_df, SUO) ]

/* ------------------------------------------------------------------------- */
/* On command (not supported for OffOnly)                                    */
/* ------------------------------------------------------------------------- */

// Base: OnOff := TRUE, no timer semantics
rule Cmd_On_Base:
  [ St_Cluster(~tid, OnOff, GSC, OT, OW, TS, f_base, SUO) ]
--[ Command(~tid, 'On'), CmdSucceeded(~tid, 'On') ]->
  [ St_Cluster(~tid, b_true, GSC, OT, OW, ts_idle, f_base, SUO) ]

// DF: OnOff := TRUE
rule Cmd_On_DF:
  [ St_Cluster(~tid, OnOff, GSC, OT, OW, TS, f_df, SUO) ]
--[ Command(~tid, 'On'), CmdSucceeded(~tid, 'On') ]->
  [ St_Cluster(~tid, b_true, GSC, OT, OW, ts_idle, f_df, SUO) ]

// OffOnly: must reject with UNSUPPORTED_COMMAND
rule Cmd_On_OffOnly_Unsupported:
  [ St_Cluster(~tid, OnOff, GSC, OT, OW, TS, f_offonly, SUO) ]
--[ Command(~tid, 'On'), CmdRejected(~tid, 'On', 'UNSUPPORTED_COMMAND') ]->
  [ St_Cluster(~tid, OnOff, GSC, OT, OW, TS, f_offonly, SUO) ]

// LT: OnOff := TRUE; if OnTime == 0 then OffWaitTime := 0; GlobalSceneControl := TRUE
rule Cmd_On_LT_OnTimeZero:
  [ St_Cluster(~tid, OnOff, GSC, t_zero, OW, TS, f_lt, SUO) ]
--[ Command(~tid, 'On'), CmdSucceeded(~tid, 'On') ]->
  [ St_Cluster(~tid, b_true, b_true, t_zero, t_zero, ts_idle, f_lt, SUO) ]

rule Cmd_On_LT_OnTimeNonZero:
  [ St_Cluster(~tid, OnOff, GSC, OT, OW, TS, f_lt, SUO) ]
  [ OT = t_pos | OT = t_ffff ]
--[ Command(~tid, 'On'), CmdSucceeded(~tid, 'On') ]->
  [ St_Cluster(~tid, b_true, b_true, OT, OW, ts_idle, f_lt, SUO) ]

// LT+DF: same semantics
rule Cmd_On_LTDF_OnTimeZero:
  [ St_Cluster(~tid, OnOff, GSC, t_zero, OW, TS, f_lt_df, SUO) ]
--[ Command(~tid, 'On'), CmdSucceeded(~tid, 'On') ]->
  [ St_Cluster(~tid, b_true, b_true, t_zero, t_zero, ts_idle, f_lt_df, SUO) ]

rule Cmd_On_LTDF_OnTimeNonZero:
  [ St_Cluster(~tid, OnOff, GSC, OT, OW, TS, f_lt_df, SUO) ]
  [ OT = t_pos | OT = t_ffff ]
--[ Command(~tid, 'On'), CmdSucceeded(~tid, 'On') ]->
  [ St_Cluster(~tid, b_true, b_true, OT, OW, ts_idle, f_lt_df, SUO) ]

/* ------------------------------------------------------------------------- */
/* Toggle command (not supported for OffOnly)                                */
/* ------------------------------------------------------------------------- */

// Base: Toggle just flips OnOff

rule Cmd_Toggle_Base_From_False:
  [ St_Cluster(~tid, b_false, GSC, OT, OW, TS, f_base, SUO) ]
--[ Command(~tid, 'Toggle'), CmdSucceeded(~tid, 'Toggle') ]->
  [ St_Cluster(~tid, b_true, GSC, OT, OW, ts_idle, f_base, SUO) ]

rule Cmd_Toggle_Base_From_True:
  [ St_Cluster(~tid, b_true, GSC, OT, OW, TS, f_base, SUO) ]
--[ Command(~tid, 'Toggle'), CmdSucceeded(~tid, 'Toggle') ]->
  [ St_Cluster(~tid, b_false, GSC, OT, OW, ts_idle, f_base, SUO) ]

// DF only: same toggle on OnOff

rule Cmd_Toggle_DF_From_False:
  [ St_Cluster(~tid, b_false, GSC, OT, OW, TS, f_df, SUO) ]
--[ Command(~tid, 'Toggle'), CmdSucceeded(~tid, 'Toggle') ]->
  [ St_Cluster(~tid, b_true, GSC, OT, OW, ts_idle, f_df, SUO) ]

rule Cmd_Toggle_DF_From_True:
  [ St_Cluster(~tid, b_true, GSC, OT, OW, TS, f_df, SUO) ]
--[ Command(~tid, 'Toggle'), CmdSucceeded(~tid, 'Toggle') ]->
  [ St_Cluster(~tid, b_false, GSC, OT, OW, ts_idle, f_df, SUO) ]

// OffOnly: must reject
rule Cmd_Toggle_OffOnly_Unsupported:
  [ St_Cluster(~tid, OnOff, GSC, OT, OW, TS, f_offonly, SUO) ]
--[ Command(~tid, 'Toggle'), CmdRejected(~tid, 'Toggle', 'UNSUPPORTED_COMMAND') ]->
  [ St_Cluster(~tid, OnOff, GSC, OT, OW, TS, f_offonly, SUO) ]

// LT: Toggle and update timers
// Pseudocode: if new state OFF and OnTime == 0 then OffWaitTime := 0; if new state ON then OnTime := 0

// Case 1: OFF → ON: new OnOff=TRUE, OnTime := 0
rule Cmd_Toggle_LT_OffToOn:
  [ St_Cluster(~tid, b_false, GSC, OT, OW, TS, f_lt, SUO) ]
--[ Command(~tid, 'Toggle'), CmdSucceeded(~tid, 'Toggle') ]->
  [ St_Cluster(~tid, b_true, b_true, t_zero, OW, ts_idle, f_lt, SUO) ]

// Case 2: ON → OFF, OnTime == 0 → OffWaitTime := 0
rule Cmd_Toggle_LT_OnToOff_OnTimeZero:
  [ St_Cluster(~tid, b_true, GSC, t_zero, OW, TS, f_lt, SUO) ]
--[ Command(~tid, 'Toggle'), CmdSucceeded(~tid, 'Toggle') ]->
  [ St_Cluster(~tid, b_false, GSC, t_zero, t_zero, ts_idle, f_lt, SUO) ]

// Case 3: ON → OFF, OnTime != 0 → OffWaitTime unchanged
rule Cmd_Toggle_LT_OnToOff_OnTimeNonZero:
  [ St_Cluster(~tid, b_true, GSC, OT, OW, TS, f_lt, SUO) ]
  [ OT = t_pos | OT = t_ffff ]
--[ Command(~tid, 'Toggle'), CmdSucceeded(~tid, 'Toggle') ]->
  [ St_Cluster(~tid, b_false, GSC, OT, OW, ts_idle, f_lt, SUO) ]

// LT+DF: same timer semantics

rule Cmd_Toggle_LTDF_OffToOn:
  [ St_Cluster(~tid, b_false, GSC, OT, OW, TS, f_lt_df, SUO) ]
--[ Command(~tid, 'Toggle'), CmdSucceeded(~tid, 'Toggle') ]->
  [ St_Cluster(~tid, b_true, b_true, t_zero, OW, ts_idle, f_lt_df, SUO) ]

rule Cmd_Toggle_LTDF_OnToOff_OnTimeZero:
  [ St_Cluster(~tid, b_true, GSC, t_zero, OW, TS, f_lt_df, SUO) ]
--[ Command(~tid, 'Toggle'), CmdSucceeded(~tid, 'Toggle') ]->
  [ St_Cluster(~tid, b_false, GSC, t_zero, t_zero, ts_idle, f_lt_df, SUO) ]

rule Cmd_Toggle_LTDF_OnToOff_OnTimeNonZero:
  [ St_Cluster(~tid, b_true, GSC, OT, OW, TS, f_lt_df, SUO) ]
  [ OT = t_pos | OT = t_ffff ]
--[ Command(~tid, 'Toggle'), CmdSucceeded(~tid, 'Toggle') ]->
  [ St_Cluster(~tid, b_false, GSC, OT, OW, ts_idle, f_lt_df, SUO) ]

/* ------------------------------------------------------------------------- */
/* OffWithEffect (LT only)                                                   */
/* ------------------------------------------------------------------------- */

// Spec:
// if GlobalSceneControl == TRUE:
//   store_global_scene(); GlobalSceneControl := FALSE; OnOff := FALSE; OnTime := 0
// else:
//   OnOff := FALSE
// OffWaitTime and TimerState not specified; we keep them unchanged.

// GSC == TRUE branch
rule Cmd_OffWithEffect_LT_GSC_True:
  [ St_Cluster(~tid, OnOff, b_true, OT, OW, TS, f_lt, SUO) ]
--[ Command(~tid, 'OffWithEffect'),
    StoreGlobalScene(~tid),
    CmdSucceeded(~tid, 'OffWithEffect') ]->
  [ St_Cluster(~tid, b_false, b_false, t_zero, OW, ts_idle, f_lt, SUO) ]

rule Cmd_OffWithEffect_LTDF_GSC_True:
  [ St_Cluster(~tid, OnOff, b_true, OT, OW, TS, f_lt_df, SUO) ]
--[ Command(~tid, 'OffWithEffect'),
    StoreGlobalScene(~tid),
    CmdSucceeded(~tid, 'OffWithEffect') ]->
  [ St_Cluster(~tid, b_false, b_false, t_zero, OW, ts_idle, f_lt_df, SUO) ]

// GSC == FALSE branch – spec: only OnOff := FALSE, others unchanged
rule Cmd_OffWithEffect_LT_GSC_False:
  [ St_Cluster(~tid, OnOff, b_false, OT, OW, TS, f_lt, SUO) ]
--[ Command(~tid, 'OffWithEffect'),
    CmdSucceeded(~tid, 'OffWithEffect') ]->
  [ St_Cluster(~tid, b_false, b_false, OT, OW, TS, f_lt, SUO) ]

rule Cmd_OffWithEffect_LTDF_GSC_False:
  [ St_Cluster(~tid, OnOff, b_false, OT, OW, TS, f_lt_df, SUO) ]
--[ Command(~tid, 'OffWithEffect'),
    CmdSucceeded(~tid, 'OffWithEffect') ]->
  [ St_Cluster(~tid, b_false, b_false, OT, OW, TS, f_lt_df, SUO) ]

/* ------------------------------------------------------------------------- */
/* OnWithRecallGlobalScene (LT only)                                         */
/* ------------------------------------------------------------------------- */

// Spec:
// if GlobalSceneControl == TRUE: discard command
// else:
//   ScenesManagementCluster.recall_global_scene(); // updates OnOff (typically TRUE)
//   GlobalSceneControl := TRUE
// if supports(OnTime) and OffWaitTime and OnTime == 0: OffWaitTime := 0

// GSC == TRUE: discard
rule Cmd_OnWithRecallGlobalScene_GSC_True_LT:
  [ St_Cluster(~tid, OnOff, b_true, OT, OW, TS, f_lt, SUO) ]
--[ Command(~tid, 'OnWithRecallGlobalScene'),
    CmdRejected(~tid, 'OnWithRecallGlobalScene', 'DISCARDED') ]->
  [ St_Cluster(~tid, OnOff, b_true, OT, OW, TS, f_lt, SUO) ]

rule Cmd_OnWithRecallGlobalScene_GSC_True_LTDF:
  [ St_Cluster(~tid, OnOff, b_true, OT, OW, TS, f_lt_df, SUO) ]
--[ Command(~tid, 'OnWithRecallGlobalScene'),
    CmdRejected(~tid, 'OnWithRecallGlobalScene', 'DISCARDED') ]->
  [ St_Cluster(~tid, OnOff, b_true, OT, OW, TS, f_lt_df, SUO) ]

// GSC == FALSE: approximate recall_global_scene() by setting OnOff := TRUE
// Case OnTime == 0: OffWaitTime := 0
rule Cmd_OnWithRecallGlobalScene_GSC_False_OnTimeZero_LT:
  [ St_Cluster(~tid, OnOff, b_false, t_zero, OW, TS, f_lt, SUO) ]
--[ Command(~tid, 'OnWithRecallGlobalScene'),
    RecallGlobalScene(~tid),
    CmdSucceeded(~tid, 'OnWithRecallGlobalScene') ]->
  [ St_Cluster(~tid, b_true, b_true, t_zero, t_zero, ts_idle, f_lt, SUO) ]

rule Cmd_OnWithRecallGlobalScene_GSC_False_OnTimeZero_LTDF:
  [ St_Cluster(~tid, OnOff, b_false, t_zero, OW, TS, f_lt_df, SUO) ]
--[ Command(~tid, 'OnWithRecallGlobalScene'),
    RecallGlobalScene(~tid),
    CmdSucceeded(~tid, 'OnWithRecallGlobalScene') ]->
  [ St_Cluster(~tid, b_true, b_true, t_zero, t_zero, ts_idle, f_lt_df, SUO) ]

// GSC == FALSE: OnTime != 0: OffWaitTime unchanged
rule Cmd_OnWithRecallGlobalScene_GSC_False_OnTimeNonZero_LT:
  [ St_Cluster(~tid, OnOff, b_false, OT, OW, TS, f_lt, SUO) ]
  [ OT = t_pos | OT = t_ffff ]
--[ Command(~tid, 'OnWithRecallGlobalScene'),
    RecallGlobalScene(~tid),
    CmdSucceeded(~tid, 'OnWithRecallGlobalScene') ]->
  [ St_Cluster(~tid, b_true, b_true, OT, OW, ts_idle, f_lt, SUO) ]

rule Cmd_OnWithRecallGlobalScene_GSC_False_OnTimeNonZero_LTDF:
  [ St_Cluster(~tid, OnOff, b_false, OT, OW, TS, f_lt_df, SUO) ]
  [ OT = t_pos | OT = t_ffff ]
--[ Command(~tid, 'OnWithRecallGlobalScene'),
    RecallGlobalScene(~tid),
    CmdSucceeded(~tid, 'OnWithRecallGlobalScene') ]->
  [ St_Cluster(~tid, b_true, b_true, OT, OW, ts_idle, f_lt_df, SUO) ]

/* ------------------------------------------------------------------------- */
/* OnWithTimedOff (LT only)                                                  */
/* ------------------------------------------------------------------------- */

// Spec summary (simplified into abstract symbolic model):
// Input fields: OnOffControl (AcceptOnlyWhenOn bit), OnTimeField, OffWaitTimeField
//
// 1. If OnOffControl.AcceptOnlyWhenOn == 1 and OnOff == FALSE → discard command.
//
// 2. Delayed Off case: if OffWaitTime > 0 and OnOff == FALSE:
//      OffWaitTime := min(OffWaitTime, OffWaitTimeField);
//      state is Delayed Off.
//    We abstract min by two rules, but represent only that OffWaitTime becomes t_pos.
//
// 3. Timed On case (otherwise):
//      OnTime := max(OnTime, OnTimeField);
//      OffWaitTime := OffWaitTimeField;
//      OnOff := TRUE;
//      Start periodic timer updates:
//        While OnOff == TRUE and OnTime > 0:
//          OnTime--;
//          if OnTime == 0: OffWaitTime := 0; OnOff := FALSE;
//        While OnOff == FALSE and OffWaitTime > 0:
//          OffWaitTime--;
//    We model this by:
//      - Setting OnTime and OffWaitTime to abstract categories based on fields
//      - Setting TimerState to ts_timed_on or ts_delayed_off
//      - Separate Timer_Expire rules drive the OFF and clear timers.

// We explicitly include the control bitmap value and OnTime/OffWaitTime fields
// as action facts for observability but not in the state (parameters only).

// Helper: abstractions of OnTimeField and OffWaitTimeField into OnTime/OffWaitTime categories
// are encoded via separate command rules rather than equations.

// Case 1: AcceptOnlyWhenOn == 1 and OnOff == FALSE → discard

rule Cmd_OnWithTimedOff_Discard_AcceptOnlyWhenOn_Off_LT:
  let ctl = ctl_accept_only_when_on in
  [ St_Cluster(~tid, b_false, GSC, OT, OW, TS, f_lt, SUO) ]
--[ Command(~tid, 'OnWithTimedOff'),
    OnWithTimedOffCtl(~tid, ctl),
    CmdRejected(~tid, 'OnWithTimedOff', 'DISCARDED') ]->
  [ St_Cluster(~tid, b_false, GSC, OT, OW, TS, f_lt, SUO) ]

rule Cmd_OnWithTimedOff_Discard_AcceptOnlyWhenOn_Off_LTDF:
  let ctl = ctl_accept_only_when_on in
  [ St_Cluster(~tid, b_false, GSC, OT, OW, TS, f_lt_df, SUO) ]
--[ Command(~tid, 'OnWithTimedOff'),
    OnWithTimedOffCtl(~tid, ctl),
    CmdRejected(~tid, 'OnWithTimedOff', 'DISCARDED') ]->
  [ St_Cluster(~tid, b_false, GSC, OT, OW, TS, f_lt_df, SUO) ]

// Case 2: Delayed Off, OffWaitTime > 0 and OnOff == FALSE, AcceptOnlyWhenOn bit arbitrary

// OW > 0 (t_pos), OnOff == FALSE -> remain OFF, OffWaitTime := t_pos, TimerState := ts_delayed_off.
// We maintain OnTime as-is, but TimerState marks delayed-off countdown.
// Control bitmap can be any; we record it via action.

rule Cmd_OnWithTimedOff_DelayedOff_LT:
  let ctl = ctl_none in
  [ St_Cluster(~tid, b_false, GSC, OT, t_pos, TS, f_lt, SUO) ]
--[ Command(~tid, 'OnWithTimedOff'),
    OnWithTimedOffCtl(~tid, ctl),
    CmdSucceeded(~tid, 'OnWithTimedOff'),
    TimerStarted(~tid, 'DelayedOff') ]->
  [ St_Cluster(~tid, b_false, GSC, OT, t_pos, ts_delayed_off, f_lt, SUO) ]

rule Cmd_OnWithTimedOff_DelayedOff_LTDF:
  let ctl = ctl_none in
  [ St_Cluster(~tid, b_false, GSC, OT, t_pos, TS, f_lt_df, SUO) ]
--[ Command(~tid, 'OnWithTimedOff'),
    OnWithTimedOffCtl(~tid, ctl),
    CmdSucceeded(~tid, 'OnWithTimedOff'),
    TimerStarted(~tid, 'DelayedOff') ]->
  [ St_Cluster(~tid, b_false, GSC, OT, t_pos, ts_delayed_off, f_lt_df, SUO) ]

// Case 3: Timed On, general case (AcceptOnlyWhenOn == 0 OR OnOff == TRUE)
// We cover three abstract combinations for fields:
//   (OnTimeField = 0 , OffWaitTimeField = 0)     → (t_zero, t_zero)
//   (OnTimeField > 0, OffWaitTimeField > 0)      → (t_pos, t_pos)
//   (OnTimeField = 0xFFFF or OffWaitTimeField=0xFFFF) → we abstract as both 0xFFFF: (t_ffff, t_ffff)

// 3a) Fields Zero/Zero → OnTime := t_zero, OffWaitTime := t_zero, TimerState := ts_idle

rule Cmd_OnWithTimedOff_TimedOn_ZeroZero_LT:
  let ctl = ctl_none in
  [ St_Cluster(~tid, OnOff, GSC, OT, OW, TS, f_lt, SUO) ]
--[ Command(~tid, 'OnWithTimedOff'),
    OnWithTimedOffCtl(~tid, ctl),
    OnWithTimedOffFields(~tid, field_zero, field_zero),
    CmdSucceeded(~tid, 'OnWithTimedOff') ]->
  [ St_Cluster(~tid, b_true, GSC, t_zero, t_zero, ts_idle, f_lt, SUO) ]

