/* ------------------------------------------------------------------------- */
/* Timer expiry (abstract, no arithmetic)                                    */
/* ------------------------------------------------------------------------- */

// Timed On expiry: when in ts_timed_on, model that OnTime has reached 0 and
// OnOff is forced FALSE and OffWaitTime cleared.
// We do not chain a further Delayed Off phase from Timed On expiration;
// this is a safe under-approximation for safety properties.

rule Timer_Expire_TimedOn_LT:
  [ St_Cluster(~tid, b_true, GSC, t_pos, OW, ts_timed_on, f_lt, SUO) ]
--[ TimerExpired(~tid, 'TimedOn') ]->
  [ St_Cluster(~tid, b_false, GSC, t_zero, t_zero, ts_idle, f_lt, SUO) ]

rule Timer_Expire_TimedOn_LTDF:
  [ St_Cluster(~tid, b_true, GSC, t_pos, OW, ts_timed_on, f_lt_df, SUO) ]
--[ TimerExpired(~tid, 'TimedOn') ]->
  [ St_Cluster(~tid, b_false, GSC, t_zero, t_zero, ts_idle, f_lt_df, SUO) ]

// Delayed Off expiry: when in ts_delayed_off, OffWaitTime decreases to zero;
// we simply model the final state OffWaitTime=0 and TimerState=idle.

rule Timer_Expire_DelayedOff_LT:
  [ St_Cluster(~tid, b_false, GSC, OT, t_pos, ts_delayed_off, f_lt, SUO) ]
--[ TimerExpired(~tid, 'DelayedOff') ]->
  [ St_Cluster(~tid, b_false, GSC, OT, t_zero, ts_idle, f_lt, SUO) ]

rule Timer_Expire_DelayedOff_LTDF:
  [ St_Cluster(~tid, b_false, GSC, OT, t_pos, ts_delayed_off, f_lt_df, SUO) ]
--[ TimerExpired(~tid, 'DelayedOff') ]->
  [ St_Cluster(~tid, b_false, GSC, OT, t_zero, ts_idle, f_lt_df, SUO) ]

/* ------------------------------------------------------------------------- */
/* Dead Front behavior (DF feature)                                          */
/* ------------------------------------------------------------------------- */

// Spec: When DF feature present and OnOff == FALSE, some Invoke/Write from
// other clusters may fail with INVALID_IN_STATE; reporting/events continue.

// We model that for DF devices when Off, invocations may return INVALID_IN_STATE.
// We do not prevent successful invocations; spec says "may fail", not "must".

rule DF_Invoke_May_Fail_WhenOff:
  [ St_Cluster(~tid, b_false, GSC, OT, OW, TS, F, SUO) ]
  [ F = f_df | F = f_lt_df ]
--[ InvokeStatus(~tid, op_invoke, 'INVALID_IN_STATE') ]->
  [ St_Cluster(~tid, b_false, GSC, OT, OW, TS, F, SUO) ]

rule DF_Invoke_May_Succeed:
  [ St_Cluster(~tid, OnOff, GSC, OT, OW, TS, F, SUO) ]
--[ InvokeStatus(~tid, op_invoke, 'SUCCESS') ]->
  [ St_Cluster(~tid, OnOff, GSC, OT, OW, TS, F, SUO) ]

/* ------------------------------------------------------------------------- */
/* Restrictions                                                              */
/* ------------------------------------------------------------------------- */

// Ensure TimerState is consistent with abstract timer categories
restriction timer_state_consistency:
  "All tid onoff gsc ot ow ts f suo #i.
     St_Cluster(tid,onoff,gsc,ot,ow,ts,f,suo)@i ==>
       ((ts = ts_idle) |
        (ts = ts_timed_on & onoff = b_true & ot = t_pos) |
        (ts = ts_delayed_off & onoff = b_false & ow = t_pos))"

// OffOnly: there shall be no successful On/Toggle for OffOnly feature
restriction offonly_blocks_on_toggle:
  "All tid onoff gsc ot ow ts suo #i cmd.
     St_Cluster(tid,onoff,gsc,ot,ow,ts,f_offonly,suo)@i
       ==> (All #j.
              CmdSucceeded(tid,cmd)@j
                ==> (cmd <> 'On' & cmd <> 'Toggle'))"

/* ------------------------------------------------------------------------- */
/* Lemmas                                                                    */
/* ------------------------------------------------------------------------- */

// If a command On or Toggle succeeds for a Lighting-capable device, eventually
// the device is On with GlobalSceneControl == TRUE.
lemma lt_on_implies_gsc_true [use_induction]:
  "All tid #i cmd.
     (CmdSucceeded(tid,cmd)@i &
      (cmd = 'On' | cmd = 'Toggle')) ==>
     (Ex #j onoff gsc ot ow ts suo.
        St_Cluster(tid,onoff,gsc,ot,ow,ts,f_lt,suo)@j &
        #i < #j & onoff = b_true & gsc = b_true)
     |
     (Ex #j onoff gsc ot ow ts suo.
        St_Cluster(tid,onoff,gsc,ot,ow,ts,f_lt_df,suo)@j &
        #i < #j & onoff = b_true & gsc = b_true)"

// Any INVALID_IN_STATE status implies device has DF feature and is Off at that time.
lemma df_invalid_in_state_means_off [typing]:
  "All tid #i.
     InvokeStatus(tid,op_invoke,'INVALID_IN_STATE')@i ==>
       (Ex gsc ot ow ts suo.
          St_Cluster(tid,b_false,gsc,ot,ow,ts,f_df,suo)@i) |
       (Ex gsc ot ow ts suo.
          St_Cluster(tid,b_false,gsc,ot,ow,ts,f_lt_df,suo)@i)"

// Timers that are started will eventually expire (abstract progress).
lemma timers_progress [use_induction]:
  "All tid kind #i.
     TimerStarted(tid,kind)@i ==>
       Ex #j. TimerExpired(tid,kind)@j & #i < #j"

end
